  ('real-estate-moex-02884', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關公寓大廈之管理維護等相關費用的規範，下列何者有誤？', '["專有部分之修繕與維護，由各該區分所有權人負擔其費用", "專有部分之共同壁及樓地板，其維護費用由所有住戶共同負擔，並得由公共基金支付", "共有部分及約定共同部分的修繕與管理，由管理委員會為之，費用得由區分所有權人按其共有之應有 部分比例分擔之", "約定專用部分之管理維護，由使用人為之，並負擔其費用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
