  ('real-estate-moex-02887', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列關於消費者保護法之規定，何者錯誤？', '["消費者保護團體對於同一之原因事件，致使眾多消費者受害時，得受讓20人以上消費者損害賠償請求 權後，以自己名義，提起訴訟", "消費者得於言詞辯論終結後，終止讓與損害賠償請求權，並通知法院", "消費者因同一之原因事件所提起之訴訟，因部分消費者終止讓與損害賠償請求權，致人數不足20人者， 不影響其實施訴訟之權能", "依消費者保護法所提之訴訟，因企業經營者之故意所致之損害，消費者得請求損害額 3 倍以下之懲罰 性賠償金"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02888', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '以下有關公寓大廈管理條例之規定，何者有誤？', '["區分所有權人除法律另有限制外，對其專有部分，得自由使用、收益、處分，並排除他人干涉", "專有部分不得與其所屬建築物共用部分之應有部分及其基地所有權或地上權之應有部分分離而為移轉 或設定負擔", "區分所有權人對專有部分之利用，不得有妨害建築物之正常使用及違反區分所有權人共同利益之行為", "於維護、修繕專有部分、約定專用部分或設置管線，必須使用共用部分時，不必經管理負責人或管理 委員會之同意後為之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
